-- Simple XML parser that handles entity references
-- This avoids external dependencies while being suitable for OpenResty

local XmlParser = {}
XmlParser.__index = XmlParser

-- Entity reference map
local entity_map = {
    ["&lt;"]   = "<",
    ["&gt;"]   = ">",
    ["&amp;"]  = "&",
    ["&apos;"] = "'",
    ["&quot;"] = '"',
}

-- Decode entity references in text
local function decode_entities(text)
    if not text then
        return nil
    end
    -- Decode named entities
    text = text:gsub("(&%w+;)", function(entity)
        return entity_map[entity] or entity
    end)
    -- Decode numeric entities (decimal)
    text = text:gsub("&#(%d+);", function(num)
        return string.char(tonumber(num))
    end)
    -- Decode hex numeric entities
    text = text:gsub("&#x(%x+);", function(hex)
        return string.char(tonumber(hex, 16))
    end)
    return text
end

-- Strip namespace prefix from tag name
local function strip_ns(tag)
    if not tag then
        return nil
    end
    local _, _, local_name = tag:find(":(.+)$")
    return local_name or tag
end

-- Parse attributes from a tag string
local function parse_attributes(attr_str)
    local attrs = {}
    if not attr_str or attr_str == "" then
        return attrs
    end
    for key, value in attr_str:gmatch('([%w:%-_]+)%s*=%s*"([^"]*)"') do
        attrs[key] = decode_entities(value)
    end
    for key, value in attr_str:gmatch("([%w:%-_]+)%s*=%s*'([^']*)'") do
        attrs[key] = decode_entities(value)
    end
    return attrs
end

-- Parse XML string into a Lua table structure
function XmlParser.parse(xml_str)
    if not xml_str or xml_str == "" then
        return nil, "Empty XML input"
    end

    -- Remove XML declaration
    xml_str = xml_str:gsub("<%?xml.-%?>", "")
    -- Remove comments
    xml_str = xml_str:gsub("<!%-%-.-%--%>", "")
    -- Remove CDATA sections but keep content
    xml_str = xml_str:gsub("<!%[CDATA%[(.-)%]%]>", "%1")

    local stack = {}
    local root = { children = {}, tag = "_root", attrs = {}, text = "" }
    local current = root

    table.insert(stack, current)

    local pos = 1
    while pos <= #xml_str do
        -- Find next tag
        local tag_start = xml_str:find("<", pos)
        if not tag_start then
            -- Remaining text
            local text = xml_str:sub(pos)
            text = decode_entities(text)
            if text and text:match("%S") then
                current.text = (current.text or "") .. text
            end
            break
        end

        -- Text before tag
        if tag_start > pos then
            local text = xml_str:sub(pos, tag_start - 1)
            text = decode_entities(text)
            if text and text:match("%S") then
                current.text = (current.text or "") .. text
            end
        end

        -- Closing tag
        local close_tag_end = xml_str:find("^</%s*([%w:%-_]+)%s*>", tag_start)
        if close_tag_end then
            local _, end_pos, tag_name = xml_str:find("^</%s*([%w:%-_]+)%s*>", tag_start)
            if #stack > 1 then
                table.remove(stack)
                current = stack[#stack]
            end
            pos = end_pos + 1
        else
            -- Self-closing tag or opening tag
            local _, end_pos, tag_name, attr_str = xml_str:find("^<%s*([%w:%-_]+)(.-)/%s*>", tag_start)
            if end_pos then
                -- Self-closing tag
                local node = {
                    tag = tag_name,
                    local_name = strip_ns(tag_name),
                    attrs = parse_attributes(attr_str),
                    children = {},
                    text = "",
                }
                table.insert(current.children, node)
                pos = end_pos + 1
            else
                -- Opening tag
                _, end_pos, tag_name, attr_str = xml_str:find("^<%s*([%w:%-_]+)(.-[^/])%s*>", tag_start)
                if not end_pos then
                    _, end_pos, tag_name = xml_str:find("^<%s*([%w:%-_]+)%s*>", tag_start)
                    attr_str = ""
                end
                if end_pos then
                    local node = {
                        tag = tag_name,
                        local_name = strip_ns(tag_name),
                        attrs = parse_attributes(attr_str or ""),
                        children = {},
                        text = "",
                    }
                    table.insert(current.children, node)
                    table.insert(stack, node)
                    current = node
                    pos = end_pos + 1
                else
                    -- Skip unrecognized content
                    pos = tag_start + 1
                end
            end
        end
    end

    if #root.children == 0 then
        return nil, "No root element found"
    end

    return root.children[1], nil
end

-- Find a child node by local name (namespace-agnostic)
local function find_child(node, local_name)
    if not node or not node.children then
        return nil
    end
    for _, child in ipairs(node.children) do
        if child.local_name == local_name or child.tag == local_name then
            return child
        end
    end
    return nil
end

-- Find all children by local name
local function find_children(node, local_name)
    local results = {}
    if not node or not node.children then
        return results
    end
    for _, child in ipairs(node.children) do
        if child.local_name == local_name or child.tag == local_name then
            table.insert(results, child)
        end
    end
    return results
end

-- Recursively find a descendant node by local name
local function find_descendant(node, local_name)
    if not node or not node.children then
        return nil
    end
    for _, child in ipairs(node.children) do
        if child.local_name == local_name or child.tag == local_name then
            return child
        end
        local found = find_descendant(child, local_name)
        if found then
            return found
        end
    end
    return nil
end

-- Get text content of a node (including nested text)
local function get_text(node)
    if not node then
        return nil
    end
    if node.text and node.text ~= "" then
        return node.text
    end
    -- Collect text from children if leaf-like
    local parts = {}
    if node.text and node.text ~= "" then
        table.insert(parts, node.text)
    end
    return #parts > 0 and table.concat(parts) or nil
end

-- Convert a node and its children to a flat Lua table
local function node_to_table(node)
    if not node then
        return nil
    end
    if #node.children == 0 then
        return get_text(node)
    end
    local result = {}
    for _, child in ipairs(node.children) do
        local key = child.local_name or child.tag
        local value = node_to_table(child)
        if result[key] then
            -- Convert to array if multiple children with same name
            if type(result[key]) ~= "table" or result[key][1] == nil then
                result[key] = { result[key] }
            end
            table.insert(result[key], value)
        else
            result[key] = value
        end
    end
    return result
end

-- Extract SOAP envelope components
local function parse_soap_envelope(root)
    local envelope = {}

    -- Determine SOAP version from namespace
    local tag = root.tag or ""
    if tag:find("Envelope") then
        for attr_name, attr_val in pairs(root.attrs or {}) do
            if attr_val:find("schemas.xmlsoap.org/soap/envelope") then
                envelope.soap_version = "1.1"
            elseif attr_val:find("www.w3.org/2003/05/soap%-envelope") then
                envelope.soap_version = "1.2"
            end
        end
        if not envelope.soap_version then
            envelope.soap_version = "1.1" -- default
        end
    else
        return nil, "Root element is not a SOAP Envelope"
    end

    -- Extract Header
    local header_node = find_child(root, "Header")
    if header_node then
        envelope.header = node_to_table(header_node)
        envelope.header_node = header_node
    end

    -- Extract Body
    local body_node = find_child(root, "Body")
    if not body_node then
        return nil, "SOAP Body not found"
    end
    envelope.body = node_to_table(body_node)
    envelope.body_node = body_node

    -- Extract the operation (first child of Body)
    if body_node.children and #body_node.children > 0 then
        local operation_node = body_node.children[1]
        envelope.operation = operation_node.local_name or operation_node.tag
        envelope.operation_node = operation_node
        envelope.operation_data = node_to_table(operation_node)
    end

    -- Check for SOAP Fault
    local fault_node = find_child(body_node, "Fault")
    if fault_node then
        envelope.is_fault = true
        envelope.fault = node_to_table(fault_node)
    else
        envelope.is_fault = false
    end

    return envelope, nil
end

-- Build a SOAP fault response XML
local function build_soap_fault(fault_code, fault_string, detail, soap_version)
    soap_version = soap_version or "1.1"

    if soap_version == "1.1" then
        local xml = '<?xml version="1.0" encoding="UTF-8"?>\n'
            .. '<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">\n'
            .. '  <soap:Body>\n'
            .. '    <soap:Fault>\n'
            .. '      <faultcode>' .. (fault_code or "soap:Server") .. '</faultcode>\n'
            .. '      <faultstring>' .. (fault_string or "Internal Server Error") .. '</faultstring>\n'
        if detail then
            xml = xml .. '      <detail>' .. detail .. '</detail>\n'
        end
        xml = xml .. '    </soap:Fault>\n'
            .. '  </soap:Body>\n'
            .. '</soap:Envelope>'
        return xml
    else
        -- SOAP 1.2
        local xml = '<?xml version="1.0" encoding="UTF-8"?>\n'
            .. '<soap:Envelope xmlns:soap="http://www.w3.org/2003/05/soap-envelope">\n'
            .. '  <soap:Body>\n'
            .. '    <soap:Fault>\n'
            .. '      <soap:Code><soap:Value>' .. (fault_code or "soap:Receiver") .. '</soap:Value></soap:Code>\n'
            .. '      <soap:Reason><soap:Text xml:lang="en">' .. (fault_string or "Internal Server Error") .. '</soap:Text></soap:Reason>\n'
        if detail then
            xml = xml .. '      <soap:Detail>' .. detail .. '</soap:Detail>\n'
        end
        xml = xml .. '    </soap:Fault>\n'
            .. '  </soap:Body>\n'
            .. '</soap:Envelope>'
        return xml
    end
end

-- Build a simple SOAP response XML
local function build_soap_response(operation_name, response_data, soap_version)
    soap_version = soap_version or "1.1"
    local ns_uri
    if soap_version == "1.1" then
        ns_uri = "http://schemas.xmlsoap.org/soap/envelope/"
    else
        ns_uri = "http://www.w3.org/2003/05/soap-envelope"
    end

    local function serialize_table(tbl, indent)
        indent = indent or "        "
        local parts = {}
        for key, value in pairs(tbl) do
            if type(value) == "table" then
                if value[1] then
                    -- Array
                    for _, item in ipairs(value) do
                        if type(item) == "table" then
                            table.insert(parts, indent .. "<" .. key .. ">\n" .. serialize_table(item, indent .. "  ") .. indent .. "</" .. key .. ">\n")
                        else
                            table.insert(parts, indent .. "<" .. key .. ">" .. tostring(item) .. "</" .. key .. ">\n")
                        end
                    end
                else
                    table.insert(parts, indent .. "<" .. key .. ">\n" .. serialize_table(value, indent .. "  ") .. indent .. "</" .. key .. ">\n")
                end
            else
                table.insert(parts, indent .. "<" .. key .. ">" .. tostring(value) .. "</" .. key .. ">\n")
            end
        end
        return table.concat(parts)
    end

    local response_tag = operation_name .. "Response"
    local body_content = serialize_table(response_data or {})

    local xml = '<?xml version="1.0" encoding="UTF-8"?>\n'
        .. '<soap:Envelope xmlns:soap="' .. ns_uri .. '">\n'
        .. '  <soap:Body>\n'
        .. '    <' .. response_tag .. '>\n'
        .. body_content
        .. '    </' .. response_tag .. '>\n'
        .. '  </soap:Body>\n'
        .. '</soap:Envelope>'
    return xml
end

